-- Ken's Hardened V2 Fix

local b64_0x1l1Il1 = {}
local char_0x1I1II1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xllIIll=1,#char_0x1I1II1 do b64_0x1l1Il1[char_0x1I1II1:sub(i_0xllIIll,i_0xllIIll)] = i_0xllIIll - 1 end

function b64_0x1l1Il1.dec_0x11lllI(d_0xIlll11)
    d_0xIlll11 = string.gsub(d_0xIlll11, '[^'..char_0x1I1II1..'=]', '')
    local r_0xll1llI = {}
    for i_0xllIIll=1, #d_0xIlll11, 4 do
        local c_0x1I111I = b64_0x1l1Il1[d_0xIlll11:sub(i_0xllIIll,i_0xllIIll)] or 0
        local c_0xlllllI = b64_0x1l1Il1[d_0xIlll11:sub(i_0xllIIll+1,i_0xllIIll+1)] or 0
        local c_0xIl1IIl, c_0xIIlIlI = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIlll11:sub(i_0xllIIll+2,i_0xllIIll+2)
        if ch3 == "=" then has3 = false else c_0xIl1IIl = b64_0x1l1Il1[ch3] or 0 end
        local ch4 = d_0xIlll11:sub(i_0xllIIll+3,i_0xllIIll+3)
        if ch4 == "=" then has4 = false else c_0xIIlIlI = b64_0x1l1Il1[ch4] or 0 end
        local b_0x11IIlI = c_0x1I111I * (2^18) + c_0xlllllI * (2^12) + c_0xIl1IIl * (2^6) + c_0xIIlIlI
        local b_0xllIIlI = math.floor(b_0x11IIlI / (2^16)) % (2^8)
        local b_0xlll1lI = math.floor(b_0x11IIlI / (2^8)) % (2^8)
        local b_0xII1Ill = b_0x11IIlI % (2^8)
        table.insert(r_0xll1llI, string.char(b_0xllIIlI))
        if has3 then table.insert(r_0xll1llI, string.char(b_0xlll1lI)) end
        if has4 then table.insert(r_0xll1llI, string.char(b_0xII1Ill)) end
    end
    return table.concat(r_0xll1llI)
end


local function bxor_0x1lIIII(a_0x1lIlI1,b_0xIIllII)
    if bit32 then return bit32.bxor(a_0x1lIlI1,b_0xIIllII) end
    local r_0xlIlIl1 = 0
    for i_0xII11lI = 0, 7 do
        local x_0xl1IIlI = a_0x1lIlI1 % 2
        local y_0xlI1lll = b_0xIIllII % 2
        if x_0xl1IIlI ~= y_0xlI1lll then r_0xlIlIl1 = r_0xlIlIl1 + (2^i_0xII11lI) end
        a_0x1lIlI1 = math.floor(a_0x1lIlI1 / 2)
        b_0xIIllII = math.floor(b_0xIIllII / 2)
    end
    return r_0xlIlIl1
end


local function bxor_str_0xllI1II(s_0xIII1lI, k_0xlllllI)
    local r_0xI1II1l = {}
    for i_0xll1lIl=1, #s_0xIII1lI do
        local b_0xlllIlI = string.byte(s_0xIII1lI, i_0xll1lIl)
        local kb_0x1ll1lI = string.byte(k_0xlllllI, (i_0xll1lIl-1) % #k_0xlllllI + 1)
        r_0xI1II1l[i_0xll1lIl] = string.char(bxor_0x1lIIII(b_0xlllIlI, kb_0x1ll1lI))
    end
    return table.concat(r_0xI1II1l)
end


local function getkeys_0x1I11I1()
    local seed = b64_0x1l1Il1.dec_0x11lllI("Q0FZMlMwdzQ=")
    local k1_enc = b64_0x1l1Il1.dec_0x11lllI("MTtgez94FUU=")
    local k2_enc = b64_0x1l1Il1.dec_0x11lllI("FCwYazRjP0c=")
    return bxor_str_0xllI1II(k1_enc, seed), bxor_str_0xllI1II(k2_enc, seed)
end


local function cff_0xlIIlll(a_0xIlIIl1)
    local st_0x1IlI1I = 0
    local res_0x1IIlII = a_0xIlIIl1
    while true do
        if st_0x1IlI1I == 0 then
            res_0x1IIlII = res_0x1IIlII + 1
            st_0x1IlI1I = 1
        elseif st_0x1IlI1I == 1 then
            res_0x1IIlII = res_0x1IIlII * 2
            st_0x1IlI1I = 2
        elseif st_0x1IlI1I == 2 then
            res_0x1IIlII = res_0x1IIlII - 3
            st_0x1IlI1I = 3
        else
            break
        end
    end
    return res_0x1IIlII
end


local function chain_0xIIl1l1(x) return x*2 end
local function chain_0xl11lll(x) return chain_0xIIl1l1(x)+1 end


local d_0xIllIll = {
  {op=255, val="", is_enc=true},
}
local pc_0xIllIlI = 1
local stk_0xlIII1I = {}
stk_0xlIII1I._jmp = nil


local disp_0xlIIIIl = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x1I11I1()

local state_0xlIll1l = 0
while true do
    if state_0xlIll1l == 0 then  -- FETCH
        if pc_0xIllIlI > #d_0xIllIll then break end
        local inst = d_0xIllIll[pc_0xIllIlI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0x1l1Il1.dec_0x11lllI(val)
            d = bxor_str_0xllI1II(d, k2)
            val = bxor_str_0xllI1II(d, k1)
        end
        stk_0xlIII1I._jmp = nil
        pc_0xIllIlI = pc_0xIllIlI + 1
        cur_op_0xllIlII = opcode
        cur_val_0x11I1l1 = val
        state_0xlIll1l = 1

    elseif state_0xlIll1l == 1 then  -- EXECUTE
        local handler = disp_0xlIIIIl[cur_op_0xllIlII]
        if handler then
            handler(stk_0xlIII1I, cur_val_0x11I1l1)
        end
        if stk_0xlIII1I._jmp then
            pc_0xIllIlI = pc_0xIllIlI + stk_0xlIII1I._jmp
        end
        state_0xlIll1l = 0
    else
        break
    end
end
